using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed.
            // EF Core 9 writes "$type" by default; existing 500K documents use "Discriminator".
            // Without this, queries return zero rows and direct SQL referencing
            // c.Discriminator stops matching.
            entity.HasDiscriminator<string>("Discriminator")
                  .HasValue("Product");

            // BREAKING CHANGE 2 — id synthesis format changed.
            // EF8: "Product|123"  EF9: "123"
            // Existing documents use the old format; reads will fail without this.
            entity.Property<string>("__id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();

            // BREAKING CHANGE 3 — HasIndex() now throws for the Cosmos provider
            // (it was silently ignored in EF8). Removed.
        });
    }
}

/// <summary>
/// Reproduces the EF Core 8 id format ("EntityType|PrimaryKey") so that
/// new documents stay compatible with the 500K existing ones.
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
    {
        var typeName = entry.Metadata.ShortName();
        var key = entry.Property("Id").CurrentValue;
        return $"{typeName}|{key}";
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; }
}

