using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // BREAKING CHANGE 4 — Synchronous I/O now throws at runtime.
    // EF Core 9 Cosmos provider removed sync support; use async throughout.
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — works because we preserved "Discriminator" as
        // the JSON property name (see ProductContext breaking change 1).
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products
            .Where(p => p.Sku == "ABC")
            .ToListAsync();
    }
}

